<span class="line"><span style="color:#F9E2AF;font-style:italic;">    #</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">serde</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">rename </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;mimeType&quot;</span><span style="color:#9399B2;">)]</span></span>
